"""
============================================================
МОДУЛЬ: forms.py
============================================================
НАЗНАЧЕНИЕ: Содержит формы для аутентификации и управления сотрудниками

АВТОР: Студент группы М3О-217БВ
ДАТА СОЗДАНИЯ: 2026-04-02
ПОСЛЕДНЕЕ ИЗМЕНЕНИЕ: 2026-04-02

ОПИСАНИЕ:
    Модуль включает следующие классы:
    1. LoginForm - форма для входа пользователей
    2. EmployeeForm - форма для создания/редактирования сотрудников

ЗАВИСИМОСТИ:
    - django.forms - для создания форм
    - django.contrib.auth.hashers - для проверки паролей
    - .models - для работы с моделями Emploees и Logins
    - random - для генерации случайных паролей
============================================================
"""

# Импорт модуля для создания форм
from django import forms
# Импорт функции для проверки паролей
from django.contrib.auth.hashers import check_password
# Импорт моделей
from .models import Emploees, Logins
# Импорт модуля для генерации случайных чисел
import random


class LoginForm(forms.Form):
    """
    ============================================================
    КЛАСС: LoginForm (Форма входа)
    ============================================================
    НАЗНАЧЕНИЕ: Форма для аутентификации пользователей
    
    ПОЛЯ:
        login (CharField): Поле для ввода логина
        password (CharField): Поле для ввода пароля (скрытое)
    
    МЕТОДЫ:
        clean(): Проверяет существование пользователя и правильность пароля
    
    АВТОР: Студент группы М3О-217БВ
    ДАТА: 2026-04-02
    ============================================================
    """
    
    # Поле для ввода логина
    # label='Логин' - подпись поля
    # max_length=100 - максимальная длина
    # widget=forms.TextInput - HTML-виджет для ввода текста
    login = forms.CharField(
        label='Логин',
        max_length=100,
        widget=forms.TextInput(attrs={
            'class': 'form-control',      # CSS класс для стилизации
            'placeholder': 'Введите логин' # Подсказка в поле ввода
        })
    )
    
    # Поле для ввода пароля
    # widget=forms.PasswordInput - HTML-виджет для ввода пароля (скрывает символы)
    password = forms.CharField(
        label='Пароль',
        widget=forms.PasswordInput(attrs={
            'class': 'form-control',       # CSS класс для стилизации
            'placeholder': 'Введите пароль' # Подсказка в поле ввода
        })
    )
    
    def clean(self):
        """
        ========================================================
        МЕТОД: clean (переопределенный)
        ========================================================
        НАЗНАЧЕНИЕ: Валидация формы - проверка логина и пароля
        
        ПАРАМЕТРЫ:
            self - ссылка на экземпляр класса
        
        ВОЗВРАЩАЕТ:
            dict: Очищенные данные формы с добавленным объектом пользователя
        
        ИСКЛЮЧЕНИЯ:
            ValidationError: Если пользователь не найден или пароль неверен
        
        АЛГОРИТМ:
            1. Получаем очищенные данные из родительского метода
            2. Извлекаем логин и пароль
            3. Ищем пользователя в БД по логину
            4. Проверяем пароль
            5. Добавляем объект пользователя в cleaned_data
        
        ИСТОРИЯ ИЗМЕНЕНИЙ:
            2026-04-02: Создание метода
        ========================================================
        """
        # Вызов родительского метода clean для базовой валидации
        cleaned_data = super().clean()
        # Извлечение логина из очищенных данных
        login = cleaned_data.get('login')
        # Извлечение пароля из очищенных данных
        password = cleaned_data.get('password')
        
        # Проверка: оба поля не пустые
        if login and password:
            try:
                # Поиск пользователя в БД по логину
                user = Logins.objects.get(login=login)
                # Проверка пароля
                if not user.check_password(password):
                    # Если пароль неверен - генерируем исключение
                    raise forms.ValidationError("Неверный пароль")
                # Добавление объекта пользователя в очищенные данные
                cleaned_data['user'] = user
            except Logins.DoesNotExist:
                # Если пользователь не найден - генерируем исключение
                raise forms.ValidationError('Пользователь с таким логином не найден')
        # Возврат очищенных данных
        return cleaned_data


class EmployeeForm(forms.ModelForm):
    """
    ============================================================
    КЛАСС: EmployeeForm (Форма сотрудника)
    ============================================================
    НАЗНАЧЕНИЕ: Форма для создания и редактирования сотрудников
    
    ПОЛЯ КЛАССА:
        create_account (bool): Флаг создания учетной записи
    
    МЕТОДЫ:
        __init__(): Инициализация формы
        generate_login(): Генерация логина на основе ФИО (статический)
        generate_password(): Генерация случайного пароля (статический)
        save(): Сохранение сотрудника и создание учетной записи
    
    АВТОР: Студент группы М3О-217БВ
    ДАТА: 2026-04-02
    ============================================================
    """
    
    # Флаг, указывающий, нужно ли создавать учетную запись
    # По умолчанию True (при создании), при редактировании устанавливается False
    create_account = True
    
    class Meta:
        """
        ========================================================
        ВНУТРЕННИЙ КЛАСС: Meta
        ========================================================
        НАЗНАЧЕНИЕ: Метаданные для ModelForm
        
        АТРИБУТЫ:
            model (Model): Модель, с которой связана форма
            fields (list): Список полей, включаемых в форму
            labels (dict): Отображаемые названия полей
            widgets (dict): Виджеты для рендеринга полей
        ========================================================
        """
        # Связь с моделью Emploees
        model = Emploees
        # Поля, отображаемые в форме (без created_at, updated_at)
        fields = ['last_name', 'first_name', 'patronymic', 'position', 'address', 'phone']
        # Русские названия полей
        labels = {
            'last_name': 'Фамилия',
            'first_name': 'Имя',
            'patronymic': 'Отчество',
            'position': 'Должность',
            'address': 'Адрес',
            'phone': 'Телефон',
        }
        # Виджеты для стилизации полей
        widgets = {
            'last_name': forms.TextInput(attrs={
                'class': 'form-control',
                'placeholder': 'Введите фамилию'
            }),
            'first_name': forms.TextInput(attrs={
                'class': 'form-control',
                'placeholder': 'Введите имя'
            }),
            'patronymic': forms.TextInput(attrs={
                'class': 'form-control',
                'placeholder': 'Введите отчество (необязательно)'
            }),
            'position': forms.Select(attrs={
                'class': 'form-control'
            }),
            'address': forms.TextInput(attrs={
                'class': 'form-control',
                'placeholder': 'Введите адрес'
            }),
            'phone': forms.TextInput(attrs={
                'class': 'form-control',
                'placeholder': 'Введите телефон'
            }),
        }
    
    def __init__(self, *args, **kwargs):
        """
        ========================================================
        МЕТОД: __init__ (конструктор)
        ========================================================
        НАЗНАЧЕНИЕ: Инициализация формы, установка флага create_account
        
        ПАРАМЕТРЫ:
            *args: Произвольные позиционные аргументы
            **kwargs: Произвольные именованные аргументы (включая create_account)
        
        ВОЗВРАЩАЕТ:
            None
        
        ПРИМЕЧАНИЕ:
            Извлекает параметр create_account из kwargs
            Устанавливает поле patronymic как необязательное
        ========================================================
        """
        # Извлечение параметра create_account (по умолчанию True)
        self.create_account = kwargs.pop('create_account', True)
        # Вызов родительского конструктора
        super().__init__(*args, **kwargs)
        # Установка поля отчество как необязательного
        self.fields['patronymic'].required = False
    
    @staticmethod
    def generate_login(last_name, first_name):
        """
        ========================================================
        МЕТОД: generate_login (статический)
        ========================================================
        НАЗНАЧЕНИЕ: Генерация логина на основе фамилии и имени
        
        ПАРАМЕТРЫ:
            last_name (str): Фамилия сотрудника
            first_name (str): Имя сотрудника
        
        ВОЗВРАЩАЕТ:
            str: Сгенерированный уникальный логин
        
        АЛГОРИТМ:
            1. Транслитерация фамилии и имени с помощью словаря
            2. Объединение в формате "фамилия_имя"
            3. Проверка уникальности в БД
            4. Если логин занят, добавляет числовой суффикс
        
        ПРИМЕР:
            Иванов Иван -> ivanov_ivan
        ========================================================
        """
        # Словарь для транслитерации русских букв в латинские
        translit_dict = {
            'а': 'a', 'б': 'b', 'в': 'v', 'г': 'g', 'д': 'd', 'е': 'e', 'ё': 'e',
            'ж': 'zh', 'з': 'z', 'и': 'i', 'й': 'y', 'к': 'k', 'л': 'l', 'м': 'm',
            'н': 'n', 'о': 'o', 'п': 'p', 'р': 'r', 'с': 's', 'т': 't', 'у': 'u',
            'ф': 'f', 'х': 'kh', 'ц': 'ts', 'ч': 'ch', 'ш': 'sh', 'щ': 'sch',
            'ъ': '', 'ы': 'y', 'ь': '', 'э': 'e', 'ю': 'yu', 'я': 'ya'
        }
        
        def transliterate(text: str):
            """
            ВНУТРЕННЯЯ ФУНКЦИЯ: transliterate
            НАЗНАЧЕНИЕ: Транслитерация строки с русского на латиницу
            ПАРАМЕТРЫ: text (str) - исходный текст
            ВОЗВРАЩАЕТ: str - транслитерированный текст
            """
            # Приведение к нижнему регистру
            text = text.lower()
            # Инициализация результирующей строки
            result = ''
            # Обработка каждого символа
            for char in text:
                if char in translit_dict:
                    # Замена символа по словарю
                    result += translit_dict[char]
                elif char.isalpha():
                    # Оставление латинских букв как есть
                    result += char
                else:
                    # Игнорирование прочих символов
                    result += ''
            return result
        
        # Транслитерация фамилии
        last_translit = transliterate(last_name)
        # Транслитерация имени
        first_translit = transliterate(first_name)
        
        # Формирование логина: фамилия_имя
        login = f"{last_translit}_{first_translit}"
        # Сохранение исходного логина для возможного добавления суффикса
        original_login = login
        # Счетчик для суффикса
        counter = 1
        
        # Проверка уникальности логина в БД
        while Logins.objects.filter(login=login).exists():
            # Если логин занят, добавляем числовой суффикс
            login = f"{original_login}{counter}"
            counter += 1
        
        return login
    
    @staticmethod
    def generate_password():
        """
        ========================================================
        МЕТОД: generate_password (статический)
        ========================================================
        НАЗНАЧЕНИЕ: Генерация случайного пароля из 4 цифр
        
        ВОЗВРАЩАЕТ:
            str: Случайный пароль из 4 цифр
        
        ПРИМЕР:
            3847, 9215, 6732
        
        ПРИМЕЧАНИЕ:
            Используется random.randint(1000, 9999) для генерации
        ========================================================
        """
        # Генерация случайного числа от 1000 до 9999 и преобразование в строку
        return f"{random.randint(1000, 9999)}"
    
    def save(self, commit=True):
        """
        ========================================================
        МЕТОД: save (переопределенный)
        ========================================================
        НАЗНАЧЕНИЕ: Сохраняет сотрудника и создает учетную запись
        
        ПАРАМЕТРЫ:
            commit (bool): Если True - сохраняет в БД, если False - только создает объект
        
        ВОЗВРАЩАЕТ:
            tuple: (employee, login, password) - сотрудник и его учетные данные
        
        АЛГОРИТМ:
            1. Сохранение сотрудника через родительский метод
            2. Если commit=True и create_account=True:
               - Генерация логина и пароля
               - Создание учетной записи в Logins
               - Хеширование пароля
            3. Возврат кортежа с сотрудником и учетными данными
        
        ПРИМЕЧАНИЕ:
            При редактировании (create_account=False) учетная запись не создается
        ========================================================
        """
        # Сохранение сотрудника через родительский метод
        employee = super().save(commit=commit)
        # Инициализация переменных для учетных данных
        login = None
        password = None
        
        # Создание учетной записи только если нужно (при добавлении)
        if commit and self.create_account:
            # Генерация логина на основе ФИО сотрудника
            login = self.generate_login(employee.last_name, employee.first_name)
            # Генерация случайного пароля
            password = self.generate_password()
            # Создание объекта учетной записи
            user_account = Logins(
                employee=employee,  # Связь с сотрудником
                login=login        # Установка логина
            )
            # Установка хешированного пароля
            user_account.set_password(password)
            # Сохранение учетной записи в БД
            user_account.save()
        
        # Возврат кортежа: сотрудник, логин, пароль
        return employee, login, password